local function decode(s)
    local t = {}
    for num in string.gmatch(s, "%d+") do
        table.insert(t, string.char(tonumber(num)))
    end
    return table.concat(t)
end

local func, err = loadstring(decode(data))
if func then
    func()
else
    warn("Failed to load script: " .. tostring(err))
end
